#include <stdio.h>
#include <stdlib.h>

int main(int argc, char *argv[]) {
    int num1, num2, sum;

    // Validate number of arguments
    if (argc != 3) {
        printf("Usage: %s <number1> <number2>\n", argv[0]);
        return 1;
    }

    // Convert string arguments to integers
    num1 = atoi(argv[1]);
    num2 = atoi(argv[2]);

    // Calculate sum
    sum = num1 + num2;

    printf("Sum of %d and %d = %d\n", num1, num2, sum);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(int argc, char *argv[]) {
    int num1, num2, result;
    char operator;

    // Validate arguments
    if (argc != 4) {
        printf("Usage: %s <num1> <operator> <num2>\n", argv[0]);
        printf("Operators: + - * /\n");
        return 1;
    }

    // Convert arguments
    num1 = atoi(argv[1]);
    operator = argv[2][0];  // Get first character
    num2 = atoi(argv[3]);

    // Perform operation
    switch(operator) {
        case '+':
            result = num1 + num2;
            printf("%d + %d = %d\n", num1, num2, result);
            break;
        case '-':
            result = num1 - num2;
            printf("%d - %d = %d\n", num1, num2, result);
            break;
        case '*':
            result = num1 * num2;
            printf("%d * %d = %d\n", num1, num2, result);
            break;
        case '/':
            if (num2 == 0) {
                printf("Error: Division by zero!\n");
                return 1;
            }
            result = num1 / num2;
            printf("%d / %d = %d\n", num1, num2, result);
            break;
        default:
            printf("Error: Invalid operator '%c'\n", operator);
            return 1;
    }

    return 0;
}
